let source = PathBuf::from(
    env::var("DEP_JXL_PATH")
        .expect("DEP_JXL_PATH must point at external/libjxl (set in .cargo/config.toml)"),
);
assert!(
    source.join("CMakeLists.txt").exists(),
    "libjxl source not found at {} (CMakeLists.txt missing)",
    source.display()
);
